import{_ as o}from"./chunks/placeholder.DuiHaLuQ.js";import{_ as a,o as c,c as s,ag as d}from"./chunks/framework.DXGyWiRo.js";const n="/media/202304/2023-04-04_150524_5120620.06382676679950139.png",l="/media/202304/2023-04-04_150551_0378930.06633168361832742.png",g=JSON.parse('{"title":"意图和语料","description":"","frontmatter":{"title":"意图和语料"},"headers":[],"relativePath":"custom-biz/skill-studio/intents.md","filePath":"custom-biz/skill-studio/intents.md","lastUpdated":null}'),i={name:"custom-biz/skill-studio/intents.md"};function t(p,e,r,u,h,m){return c(),s("div",null,[...e[0]||(e[0]=[d(`<p><strong>目录</strong></p><ol><li>意图 1.1. 意图分类 1.2. 意图类型切换</li><li>语料 2.1. 语料分类 2.2. 语料编写 2.3. 标签符号说明</li><li>词槽</li></ol><h2 id="意图" tabindex="-1">意图 <a class="header-anchor" href="#意图" aria-label="Permalink to &quot;意图&quot;">​</a></h2><p>意图指一个明确的用户目的。<code>例：餐厅技能包含订位、点餐意图</code> 意图是技能的基础组成部分，每个意图一般代表一个或一组功能。</p><h3 id="_1-1-意图分类" tabindex="-1">1.1. 意图分类 <a class="header-anchor" href="#_1-1-意图分类" aria-label="Permalink to &quot;1.1. 意图分类&quot;">​</a></h3><ul><li><strong>入口意图</strong>：不需要历史信息就响应用户</li><li><strong>对话意图</strong>：为了减少不同技能的说法串扰，先命中A技能的入口意图，才能命中A技能的对话意图。存在历史交互信息，响应存在上下文关联。</li></ul><p>示例：</p><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 正常命中</span></span>
<span class="line"><span>用户：今天天气   （入口意图）</span></span>
<span class="line"><span>AIUI：晴</span></span>
<span class="line"><span>用户：明天呢     （对话意图）</span></span>
<span class="line"><span>AIUI：阴天</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br><span class="line-number">4</span><br><span class="line-number">5</span><br></div></div><div class="language-text vp-adaptive-theme line-numbers-mode"><button title="Copy Code" class="copy"></button><span class="lang">text</span><pre class="shiki shiki-themes github-light github-dark vp-code" tabindex="0"><code><span class="line"><span>// 无法命中</span></span>
<span class="line"><span>用户：明天呢     （对话意图）</span></span>
<span class="line"><span>AIUI：对不起，我没听懂 （未命中）</span></span></code></pre><div class="line-numbers-wrapper" aria-hidden="true"><span class="line-number">1</span><br><span class="line-number">2</span><br><span class="line-number">3</span><br></div></div><p>「明天呢」没有单独存在的意义，系统不响应。只有具备历史信息后，对话意图才响应用户。</p><h3 id="_1-2-意图类型切换" tabindex="-1">1.2. 意图类型切换 <a class="header-anchor" href="#_1-2-意图类型切换" aria-label="Permalink to &quot;1.2. 意图类型切换&quot;">​</a></h3><ol><li>打开意图，并点击<code>意图信息</code>内的<code>编辑</code>按钮 <img src="`+n+'" alt="" title="null"></li><li>切换后保存 <img src="'+l+'" alt="" title="null"></li></ol><h2 id="语料" tabindex="-1">语料 <a class="header-anchor" href="#语料" aria-label="Permalink to &quot;语料&quot;">​</a></h2><p>意图一般是一类语料的集合，以实现某个或某组功能。用户说法多样，技能应尽可能完善语料，否则系统无法理解。语料由槽位及其他文本内容构成，每个槽位都可绑定一个实体、辅助词或通配实体（特殊实体）等元素，相关介绍可见<a href="/custom-biz/skill-studio/entities.html" title="实体和辅助词">实体和辅助词</a>。 示例：</p><ul><li>今天天气</li><li>今天下雨吗</li><li>告诉我今天天气</li><li>……</li></ul><h3 id="_2-1-语料分类" tabindex="-1">2.1. 语料分类 <a class="header-anchor" href="#_2-1-语料分类" aria-label="Permalink to &quot;2.1. 语料分类&quot;">​</a></h3><p><strong>模版语料（推荐）</strong>：由<code>{词槽}</code>和文本构成，<code>{}</code>内为槽位，每个词槽都可以绑定实体或辅助词。 <code>例：{time}天气</code><strong>例句语料</strong>：由纯文本构成，可用鼠标选择其中的词来配置词槽和绑定实体、辅助词。 <code>例：今天天气</code></p><p><strong>例句语料和模板语料无法在一个意图中共存，会导致无法正常命中。</strong></p><p><strong>语料类型区分</strong> ：</p><p><img src="'+o+'" alt="待补充：语料类型示例与模板示意图"></p><h3 id="_2-2-语料编写" tabindex="-1">2.2. 语料编写 <a class="header-anchor" href="#_2-2-语料编写" aria-label="Permalink to &quot;2.2. 语料编写&quot;">​</a></h3><p>模版语料仅支持汉字、数字、字母及<code>&lt;&gt;</code>、<code>{}</code>、<code>[]</code>、<code>()</code>、<code>,</code>、<code>。</code>，<code>.</code>、<code>!</code>、<code>?</code>、<code>%</code>、<code>|</code>、<code>+</code>、<code>-</code>、<code>×</code>、<code>*</code>、<code>÷</code>、<code>/</code>、<code>_</code>、<code>#</code>、<code>&#39;</code>、<code>&quot;</code>、<code>°</code>、<code>=</code>。</p><p>例句语料仅支持<code>,</code>、<code>。</code>、<code>.</code>、<code>!</code>、<code>?</code>、<code>%</code>、<code>+</code>、<code>-</code>、<code>×</code>、<code>*</code>、<code>÷</code>、<code>/</code>、<code>_</code>、<code>#</code>、<code>&#39;</code>、<code>&quot;</code>、<code>°</code>、<code>=</code>。</p><h3 id="_2-3-标签符号说明" tabindex="-1">2.3. 标签符号说明 <a class="header-anchor" href="#_2-3-标签符号说明" aria-label="Permalink to &quot;2.3. 标签符号说明&quot;">​</a></h3><p><code>{}</code>：代表词槽，内容仅支持：字母、数字、下划线<code>_</code>、小数点<code>.</code>、井号<code>#</code>。输入该符号，则语料强制转为模板语料，成对出现。例：{time}天气</p><p><code>()</code>：代表必选，内容支持词槽、汉字等。输入后语料强制转为模板语料，每句语料最多配置5对。 <code>例:（今天|今天的）天气</code>等同于</p><ul><li>今天天气</li><li>今天的天气</li></ul><p><code>|</code>：代表或，仅推荐出现在<code>()</code>中</p><p><code>[]</code>：代表内容可有可无，包含词槽、汉字、字母等。输入后语料强制转为模板语料，每句语料最多配置5对。 例:[今天][今天的]天气 等同于</p><ul><li>天气</li><li>今天天气</li><li>今天的天气 <blockquote><p><em>例句语料如需配置词槽可有可无，可将对应词槽转换为辅助词，并取消勾选表述必须</em>。</p></blockquote></li></ul><h2 id="词槽" tabindex="-1">词槽 <a class="header-anchor" href="#词槽" aria-label="Permalink to &quot;词槽&quot;">​</a></h2><p>词槽内容建议使用字母、数字及<code>_</code></p>',32)])])}const k=a(i,[["render",t]]);export{g as __pageData,k as default};
